import {
  SortableContext,
  horizontalListSortingStrategy,
} from "@dnd-kit/sortable";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import type { MediaCarouselItem, MediaKind } from "../types";
import { MediaDropzone } from "./media-dropzone";
