export interface PreviewRailProps {
  items: MediaCarouselItem[];
  selectedId: string | null;
  /** Editing in progress → the whole rail is read-only. */
  disabled: boolean;
  canAddMore: boolean;
  accept: MediaKind[];
  maxItems: number;
  labels: {
    remove: string;
    reorderHint: string;
    itemAria: string;
    dropzoneTitle: string;
    dropzoneBrowse: string;
    dropzoneHint: string;
    addMore: string;
  };
  onSelect: (id: string) => void;
  onRemove: (id: string) => void;
  onFiles: (files: FileList) => void;
}

/**
 * Horizontal thumbnail strip. `SortableContext` (horizontal strategy) drives
 * reorder; the wrapping `DndContext` lives in the root component. A trailing
 * compact dropzone tile adds more items when under `maxItems` and not editing.
 */
export function PreviewRail({
  items,
  selectedId,
  disabled,
  canAddMore,
  accept,
  maxItems,
  labels,
  onSelect,
  onRemove,
  onFiles,
}: PreviewRailProps) {
  return (
    <ScrollArea className="w-full">
      <div className="flex items-center gap-2 p-1">
        <SortableContext
          items={items.map((it) => it.id)}
          strategy={horizontalListSortingStrategy}
        >
          {items.map((item, i) => (
            <RailThumb
              key={item.id}
              item={item}
              index={i}
              total={items.length}
              selected={item.id === selectedId}
              disabled={disabled}
              labels={labels}
              onSelect={onSelect}
              onRemove={onRemove}
            />
          ))}
        </SortableContext>
        {canAddMore && !disabled ? (
          <MediaDropzone
            variant="add-more"
            accept={accept}
            maxItems={maxItems}
            labels={labels}
            onFiles={onFiles}
          />
        ) : null}
      </div>
      <ScrollBar orientation="horizontal" />
    </ScrollArea>
  );
}

